import React, { useState } from "react";
import AddExpense from "./AddExpense";

const AddNew = ({ employee }) => {
  const [selectedType, setSelectedType] = useState(null);

  if (!employee) {
    return (
      <div
        style={{
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontFamily: "Segoe UI",
        }}
      >
        <p>Loading employee...</p>
      </div>
    );
  }

  // If user clicked Travel / Ticket → show full page AddExpense
  if (selectedType) {
    return (
      <AddExpense
        type={selectedType} // "travel" or "ticket"
        employee={employee}
        onBack={() => setSelectedType(null)}
      />
    );
  }

  // Default screen → 2 big cards in center
  return (
    <div
      style={{
        fontFamily: "Segoe UI",
        background: "#f5f7fb",
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      <div
        style={{
          maxWidth: 900,
          width: "100%",
          background: "white",
          borderRadius: 16,
          boxShadow: "0 8px 24px rgba(0,0,0,0.08)",
          padding: 24,
        }}
      >
        {/* Header */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: 20,
          }}
        >
          <div>
            <h2 style={{ margin: 0, color: "#1b3b5f" }}>Add New Expense</h2>
            <p style={{ margin: "6px 0 0", color: "#607089" }}>
              Choose what you want to add for{" "}
              <strong>{employee.name}</strong> ({employee.emp_code})
            </p>
          </div>

          <button
            onClick={() => window.history.back()}
            style={{
              border: "1px solid #d0d7e2",
              background: "#fff",
              borderRadius: 8,
              padding: "6px 12px",
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
        </div>

        {/* Two big cards */}
        <div
          style={{
            display: "flex",
            gap: 24,
            flexWrap: "wrap",
            justifyContent: "center",
            marginTop: 10,
          }}
        >
          {/* Travel card */}
          <div
            onClick={() => setSelectedType("travel")}
            style={{
              flex: "1 1 260px",
              maxWidth: 360,
              borderRadius: 16,
              padding: 24,
              background:
                "linear-gradient(145deg, #e3f2fd 0%, #ffffff 40%, #bbdefb 100%)",
              boxShadow: "0 10px 30px rgba(25,118,210,0.25)",
              cursor: "pointer",
              transition: "transform 0.15s ease, box-shadow 0.15s ease",
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-4px)";
              e.currentTarget.style.boxShadow =
                "0 14px 38px rgba(25,118,210,0.3)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow =
                "0 10px 30px rgba(25,118,210,0.25)";
            }}
          >
            <div style={{ fontSize: 32, marginBottom: 8 }}>🚌</div>
            <h3 style={{ margin: "0 0 4px", color: "#0d47a1" }}>
              Travel Expense
            </h3>
            <p style={{ margin: "0 0 12px", color: "#37474f" }}>
              Add and manage employee travel expenses with locations, purposes,
              and approvals.
            </p>
            <ul style={{ paddingLeft: 18, margin: 0, color: "#455a64" }}>
              <li>Add new travel expense</li>
              <li>View & filter history</li>
              <li>Edit / delete records</li>
            </ul>
          </div>

          {/* Ticket card */}
          <div
            onClick={() => setSelectedType("ticket")}
            style={{
              flex: "1 1 260px",
              maxWidth: 360,
              borderRadius: 16,
              padding: 24,
              background:
                "linear-gradient(145deg, #e8f5e9 0%, #ffffff 40%, #c8e6c9 100%)",
              boxShadow: "0 10px 30px rgba(46,125,50,0.25)",
              cursor: "pointer",
              transition: "transform 0.15s ease, box-shadow 0.15s ease",
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-4px)";
              e.currentTarget.style.boxShadow =
                "0 14px 38px rgba(46,125,50,0.3)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow =
                "0 10px 30px rgba(46,125,50,0.25)";
            }}
          >
            <div style={{ fontSize: 32, marginBottom: 8 }}>🎫</div>
            <h3 style={{ margin: "0 0 4px", color: "#1b5e20" }}>
              Ticket Expense
            </h3>
            <p style={{ margin: "0 0 12px", color: "#37474f" }}>
              Add support / ticket-related expenses assigned to internal teams.
            </p>
            <ul style={{ paddingLeft: 18, margin: 0, color: "#455a64" }}>
              <li>Add new ticket expense</li>
              <li>View & filter history</li>
              <li>Edit / delete records</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AddNew;
